cat ~/.openclaw/openclaw.json | jq '. + {
  "hooks": {
    "enabled": true,
    "path": "/webhook",
    "token": "593547147a6a714e7174d65d507db75a",
    "transformsDir": "'$HOME'/.clawdbot/hooks-transforms",
    "mappings": [
      {
        "name": "mission-control",
        "match": {
          "path": "/webhook",
          "headers": {
            "x-github-event": "push"
          }
        },
        "transform": {
          "module": "github-mission-control.mjs"
        }
      }
    ],
    "internal": {
      "enabled": true,
      "entries": {
        "boot-md": { "enabled": true },
        "command-logger": { "enabled": true },
        "session-memory": { "enabled": true },
        "bootstrap-extra-files": { "enabled": true }
      }
    }
  }
}' > /tmp/openclaw-hooks-config.json && cat /tmp/openclaw-hooks-config.json | jq '.hooks'

